package com.example.authserver.service;

import org.springframework.stereotype.Service;

import java.net.IDN;
import java.net.URI;
import java.util.Locale;

@Service
public class RedirectUriValidator {

    public boolean isAllowedRedirectUri(String redirectUri, String registeredBaseUrl) {
        URI redirect = parseAbsoluteHttpsUri(redirectUri);
        URI base = parseAbsoluteHttpsUri(registeredBaseUrl);

        String redirectHost = normalizeHost(redirect.getHost());
        String baseHost = normalizeHost(base.getHost());

        if (redirectHost == null || baseHost == null) return false;

        if (!equalsIgnoreCase(redirect.getScheme(), base.getScheme())) return false;

        int redirectPort = effectivePort(redirect);
        int basePort = effectivePort(base);
        if (redirectPort != basePort) return false;

        if (!hostMatches(baseHost, redirectHost)) return false;

        String basePath = normalizePath(base.getPath());
        String redirectPath = normalizePath(redirect.getPath());

        if (!pathStartsWith(redirectPath, basePath)) return false;

        return true;
    }

    private URI parseAbsoluteHttpsUri(String s) {
        try {
            URI uri = URI.create(s);
            if (!uri.isAbsolute()) return null;
            if (uri.getScheme() == null) return null;
            if (uri.getHost() == null) return null;
            return uri;
        } catch (Exception e) {
            return null;
        }
    }

    private int effectivePort(URI uri) {
        int p = uri.getPort();
        if (p != -1) return p;
        String scheme = uri.getScheme();
        if ("https".equalsIgnoreCase(scheme)) return 443;
        if ("http".equalsIgnoreCase(scheme)) return 80;
        return -1;
    }

    private boolean equalsIgnoreCase(String a, String b) {
        if (a == null || b == null) return false;
        return a.equalsIgnoreCase(b);
    }

    private String normalizeHost(String host) {
        if (host == null) return null;
        String ascii = IDN.toASCII(host.trim(), IDN.ALLOW_UNASSIGNED);
        return ascii.toLowerCase(Locale.ROOT);
    }

    private String normalizePath(String path) {
        if (path == null || path.isEmpty()) return "/";
        if (!path.startsWith("/")) path = "/" + path;
        return path;
    }

    private boolean pathStartsWith(String actual, String base) {
        if ("/".equals(base)) return true;
        if (!actual.startsWith(base)) return false;
        if (actual.length() == base.length()) return true;
        return actual.charAt(base.length()) == '/';
    }

    private boolean hostMatches(String baseHost, String redirectHost) {
        if (baseHost.startsWith("*.")) {
            String suffix = baseHost.substring(2);
            if (suffix.isEmpty()) return false;
            if (redirectHost.equals(suffix)) return false;
            return redirectHost.endsWith("." + suffix);
        }
        return redirectHost.equals(baseHost);
    }
}

package com.example.authserver.service;

import com.example.authserver.model.AuthorizationCodeEntry;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.util.Base64;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class AuthorizationCodeStore {
    private static final long TTL_MILLIS = 10 * 60 * 1000L;

    private final Map<String, AuthorizationCodeEntry> codes = new ConcurrentHashMap<>();
    private final SecureRandom secureRandom = new SecureRandom();

    public AuthorizationCodeEntry create(String clientId,
                                         String redirectUri,
                                         String scope,
                                         String state,
                                         String subject) {
        String code = generateCode();
        long now = System.currentTimeMillis();
        AuthorizationCodeEntry entry = new AuthorizationCodeEntry(
                code, clientId, redirectUri, scope, state, subject, now + TTL_MILLIS
        );
        codes.put(code, entry);
        return entry;
    }

    public Optional<AuthorizationCodeEntry> consume(String code) {
        AuthorizationCodeEntry entry = codes.remove(code);
        if (entry == null) return Optional.empty();
        if (entry.isExpired(System.currentTimeMillis())) return Optional.empty();
        return Optional.of(entry);
    }

    public Optional<AuthorizationCodeEntry> peek(String code) {
        AuthorizationCodeEntry entry = codes.get(code);
        if (entry == null) return Optional.empty();
        if (entry.isExpired(System.currentTimeMillis())) return Optional.empty();
        return Optional.of(entry);
    }

    @Scheduled(fixedDelay = 60_000L)
    public void cleanup() {
        long now = System.currentTimeMillis();
        for (Map.Entry<String, AuthorizationCodeEntry> e : codes.entrySet()) {
            if (e.getValue().isExpired(now)) {
                codes.remove(e.getKey(), e.getValue());
            }
        }
    }

    private String generateCode() {
        byte[] bytes = new byte[32];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }
}

