package com.example.authserver.web;

import com.example.authserver.model.AuthorizationCodeEntry;
import com.example.authserver.model.RegisteredClient;
import com.example.authserver.service.AuthorizationCodeStore;
import com.example.authserver.service.ClientRegistry;
import com.example.authserver.service.RedirectUriValidator;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.util.MultiValueMap;
import org.springframework.web.bind.annotation.*;

import java.net.URI;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.Optional;

@RestController
@RequestMapping("/oauth")
public class AuthorizationController {

    private final ClientRegistry clientRegistry;
    private final RedirectUriValidator redirectUriValidator;
    private final AuthorizationCodeStore authorizationCodeStore;

    public AuthorizationController(ClientRegistry clientRegistry,
                                   RedirectUriValidator redirectUriValidator,
                                   AuthorizationCodeStore authorizationCodeStore) {
        this.clientRegistry = clientRegistry;
        this.redirectUriValidator = redirectUriValidator;
        this.authorizationCodeStore = authorizationCodeStore;
    }

    @GetMapping(value = "/authorize")
    public org.springframework.http.ResponseEntity<?> authorize(
            @RequestParam("response_type") String responseType,
            @RequestParam("client_id") String clientId,
            @RequestParam("redirect_uri") String redirectUri,
            @RequestParam(value = "scope", required = false) String scope,
            @RequestParam(value = "state", required = false) String state,
            @RequestParam(value = "subject", required = false) String subject
    ) {
        if (!"code".equals(responseType)) {
            return oauthError("unsupported_response_type", "Only response_type=code is supported", HttpStatus.BAD_REQUEST);
        }

        Optional<RegisteredClient> clientOpt = clientRegistry.findByClientId(clientId);
        if (clientOpt.isEmpty()) {
            return oauthError("unauthorized_client", "Unknown client_id", HttpStatus.BAD_REQUEST);
        }

        RegisteredClient client = clientOpt.get();

        boolean allowed = false;
        for (String baseUrl : client.getRedirectBaseUrls()) {
            if (redirectUriValidator.isAllowedRedirectUri(redirectUri, baseUrl)) {
                allowed = true;
                break;
            }
        }
        if (!allowed) {
            return oauthError("invalid_request", "Invalid redirect_uri", HttpStatus.BAD_REQUEST);
        }

        String resolvedSubject = (subject == null || subject.isBlank()) ? "user" : subject.trim();
        AuthorizationCodeEntry entry = authorizationCodeStore.create(clientId, redirectUri, scope, state, resolvedSubject);

        String location = buildRedirectWithCode(redirectUri, entry.getCode(), state);
        return org.springframework.http.ResponseEntity.status(HttpStatus.FOUND).location(URI.create(location)).build();
    }

    @PostMapping(value = "/token", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE, produces = MediaType.APPLICATION_JSON_VALUE)
    public org.springframework.http.ResponseEntity<?> token(@RequestBody MultiValueMap<String, String> form) {
        String grantType = first(form, "grant_type");
        if (!"authorization_code".equals(grantType)) {
            return oauthError("unsupported_grant_type", "Only grant_type=authorization_code is supported", HttpStatus.BAD_REQUEST);
        }

        String code = first(form, "code");
        String clientId = first(form, "client_id");
        String redirectUri = first(form, "redirect_uri");

        if (code == null || clientId == null || redirectUri == null) {
            return oauthError("invalid_request", "Missing required parameters", HttpStatus.BAD_REQUEST);
        }

        Optional<AuthorizationCodeEntry> entryOpt = authorizationCodeStore.consume(code);
        if (entryOpt.isEmpty()) {
            return oauthError("invalid_grant", "Invalid or expired code", HttpStatus.BAD_REQUEST);
        }

        AuthorizationCodeEntry entry = entryOpt.get();
        if (!entry.getClientId().equals(clientId)) {
            return oauthError("invalid_grant", "Code was not issued to this client", HttpStatus.BAD_REQUEST);
        }
        if (!entry.getRedirectUri().equals(redirectUri)) {
            return oauthError("invalid_grant", "redirect_uri mismatch", HttpStatus.BAD_REQUEST);
        }

        String accessToken = "at_" + code;
        String tokenType = "bearer";
        long expiresIn = 3600;

        String json = "{"
                + "\"access_token\":\"" + escapeJson(accessToken) + "\","
                + "\"token_type\":\"" + tokenType + "\","
                + "\"expires_in\":" + expiresIn
                + (entry.getScope() != null ? ",\"scope\":\"" + escapeJson(entry.getScope()) + "\"" : "")
                + "}";

        return org.springframework.http.ResponseEntity.ok()
                .contentType(MediaType.APPLICATION_JSON)
                .body(json);
    }

    private String buildRedirectWithCode(String redirectUri, String code, String state) {
        StringBuilder sb = new StringBuilder(redirectUri);
        if (redirectUri.contains("?")) {
            if (!redirectUri.endsWith("?") && !redirectUri.endsWith("&")) sb.append("&");
        } else {
            sb.append("?");
        }
        sb.append("code=").append(urlEncode(code));
        if (state != null) {
            sb.append("&state=").append(urlEncode(state));
        }
        return sb.toString();
    }

    private String urlEncode(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }

    private org.springframework.http.ResponseEntity<String> oauthError(String error, String desc, HttpStatus status) {
        String json = "{"
                + "\"error\":\"" + escapeJson(error) + "\","
                + "\"error_description\":\"" + escapeJson(desc) + "\""
                + "}";
        return org.springframework.http.ResponseEntity.status(status)
                .contentType(MediaType.APPLICATION_JSON)
                .body(json);
    }

    private String first(MultiValueMap<String, String> form, String key) {
        return form.getFirst(key);
    }

    private String escapeJson(String s) {
        if (s == null) return "";
        StringBuilder out = new StringBuilder(s.length() + 16);
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            switch (c) {
                case '\\': out.append("\\\\"); break;
                case '"': out.append("\\\""); break;
                case '\b': out.append("\\b"); break;
                case '\f': out.append("\\f"); break;
                case '\n': out.append("\\n"); break;
                case '\r': out.append("\\r"); break;
                case '\t': out.append("\\t"); break;
                default:
                    if (c < 0x20) {
                        out.append(String.format("\\u%04x", (int) c));
                    } else {
                        out.append(c);
                    }
            }
        }
        return out.toString();
    }
}

